const unit2Pool = [
    // CHAPTER 4: HOW COMPUTERS WORK (Standards: Abstractions, Systems, Troubleshooting)
    { chapter: 4, question: "What does the concept of 'abstraction' mean in computing systems?", options: ["Hiding complex hardware and software details to make devices easier for users to interact with.", "Translating high-level programming languages directly into binary code for the CPU.", "The physical routing of data packets across a wide area network.", "A cybersecurity protocol that encrypts user data to prevent unauthorized access."], tag: "Abstraction", hint: "Think of driving a car: you don't need to know how the engine injects fuel to press the gas pedal." },
    { chapter: 4, question: "Which of the following represents the correct hierarchy of abstraction layers in a computing system, from lowest to highest?", options: ["Hardware, System Software (OS), Application Software, User.", "System Software (OS), Hardware, User, Application Software.", "Hardware, Application Software, System Software (OS), User.", "User, System Software (OS), Application Software, Hardware."], tag: "System Layers", hint: "The physical machine is at the bottom, the OS manages the machine, the apps run on the OS, and you use the apps." },
    { chapter: 4, question: "What is the primary role of System Software (like Windows, macOS, or iOS)?", options: ["To manage the computer's hardware resources and provide a platform for application software to run.", "To directly execute high-level algorithms requested by the user.", "To compile source code into executable binary files for the CPU.", "To provide a graphical interface exclusively for word processing and web browsing."], tag: "System Software", hint: "It acts as the 'manager' or 'translator' between your hardware and your apps." },
    { chapter: 4, question: "Which of the following is the best example of Application Software?", options: ["A web browser like Google Chrome.", "A device driver that controls a printer.", "The Basic Input/Output System (BIOS) on a motherboard.", "The Linux operating system kernel."], tag: "Application Software", hint: "These are programs downloaded or installed by the user to perform specific tasks." },
    { chapter: 4, question: "How do application software and hardware communicate?", options: ["The operating system translates the application's requests into instructions the hardware can execute.", "The application communicates directly with the CPU using assembly language.", "The hardware uses an interpreter to read the application's source code in real-time.", "The application modifies the computer's BIOS settings to control hardware components."], tag: "System Interaction", hint: "Apps do not speak directly to hardware; they use the OS as a 'middleman'." },
    { chapter: 4, question: "Which phase of the information processing cycle involves a user typing on a keyboard?", options: ["Input", "Execution", "Compilation", "Storage"], tag: "Hardware", hint: "This step sends data *into* the computer system." },
    { chapter: 4, question: "Which component is responsible for the 'Logic' and 'Processing' in a computing system?", options: ["The Central Processing Unit (CPU).", "The Random Access Memory (RAM).", "The Read-Only Memory (ROM) chip.", "The solid-state drive (SSD)."], tag: "Logic & Processing", hint: "It is often referred to as the 'brain' of the computer." },
    { chapter: 4, question: "How is a smartphone's touchscreen an example of abstraction?", options: ["It allows users to open apps with a simple tap, hiding the complex code and electrical signals required to execute the command.", "It requires the operating system to bypass the CPU and process input directly through the display.", "It digitizes analog inputs by compressing the data into a smaller file size.", "It prevents users from accessing the underlying file system of the device."], tag: "Abstraction", hint: "It simplifies a highly complex technical process into a single, intuitive action." },
    { chapter: 4, question: "What is the first step in a systematic troubleshooting process?", options: ["Identify and clearly define the problem or error.", "Update the operating system to the latest available version.", "Run a comprehensive diagnostic scan on the hard drive.", "Reset the computer's BIOS to its factory default settings."], tag: "Troubleshooting", hint: "Before you can fix something, you must know exactly what is broken." },
    { chapter: 4, question: "Why is it important to change only ONE variable or setting at a time when troubleshooting?", options: ["It allows you to isolate exactly which change fixed the problem or made it worse.", "It prevents the hardware from overheating due to excessive configuration changes.", "It ensures the system memory is not overloaded by concurrent diagnostic processes.", "It automatically generates a log file that can be sent to technical support."], tag: "Troubleshooting", hint: "If you change five things and the issue goes away, you won't know which of the five things was the actual solution." },
    { chapter: 4, question: "If your computer monitor goes completely black, which troubleshooting step isolates whether it is a hardware or software issue?", options: ["Plugging the monitor into a different computer to see if it turns on.", "Pressing Ctrl+Alt+Delete to force the operating system to refresh the display driver.", "Restarting the computer multiple times in safe mode.", "Adjusting the brightness and contrast settings using the monitor's physical buttons."], tag: "Troubleshooting", hint: "Testing the component on a known working system eliminates the component as the source of the problem." },
    { chapter: 4, question: "Which of the following is considered an 'Output' device?", options: ["A pair of headphones.", "A biometric fingerprint scanner.", "A digital barcode reader.", "A USB microphone."], tag: "Hardware", hint: "Output devices take data from the computer and present it to the user." },
    { chapter: 4, question: "What is the purpose of documenting your troubleshooting steps?", options: ["To keep track of what you have already tried and to share the solution with others who might face the same error.", "To provide legal proof that the hardware malfunctioned due to manufacturer defect.", "To upload the error codes directly to the operating system's cloud database.", "To automatically reverse any software changes if the system crashes again."], tag: "Troubleshooting", hint: "Good documentation helps build guidelines so the same problem can be solved faster next time." },
    { chapter: 4, question: "Which layer of the computing system provides the actual physical capabilities, such as electrical circuitry and memory?", options: ["Hardware", "Kernel", "Firmware", "Machine Code"], tag: "Hardware", hint: "This is the layer you can physically touch." },
    { chapter: 4, question: "When a computer plays a song, how does it demonstrate the Input-Process-Output cycle?", options: ["You click 'play' (Input), the CPU decodes the audio file (Process), and the speakers generate sound (Output).", "The song is downloaded (Input), the file is saved to the hard drive (Process), and the media player opens (Output).", "The speakers generate sound (Input), the user listens to the song (Process), and the application closes (Output).", "The CPU loads the file (Input), the speakers decode the digital signal (Process), and the monitor displays the track time (Output)."], tag: "System Layers", hint: "Action triggers computation, computation yields a physical result." },

    // CHAPTER 5: LANGUAGE OF COMPUTERS (Standards: Logic, Input, Output, Data Representation)
    { chapter: 5, question: "What is the foundational language that computing systems use to process all data?", options: ["Binary", "Assembly", "Hexadecimal", "C++"], tag: "Data Representation", hint: "It is a base-2 system consisting entirely of 1s and 0s." },
    { chapter: 5, question: "What do the 1s and 0s in binary code physically represent inside a computer's hardware?", options: ["Electrical switches or transistors being turned ON (1) and OFF (0).", "Microscopic magnetic fields that are either positively or negatively charged.", "Pulses of light transmitting through the CPU's internal fiber optics.", "Data packets being routed through the motherboard's data buses."], tag: "Hardware Logic", hint: "Computers run on electricity. Binary is just a way to represent the presence or absence of an electrical current." },
    { chapter: 5, question: "How many bits (binary digits) are required to make up a single byte of data?", options: ["8", "4", "16", "32"], tag: "Data Representation", hint: "A byte is the standard chunk of data used to represent a single character, like a letter on a keyboard." },
    { chapter: 5, question: "What microscopic hardware component acts as an electrical switch to form the basis of computer logic?", options: ["Transistor", "Capacitor", "Resistor", "Diode"], tag: "Hardware", hint: "Modern CPUs contain billions of these microscopic switches." },
    { chapter: 5, question: "What type of hardware component is used to make logical decisions based on binary inputs?", options: ["Logic Gates", "Data Buses", "Registers", "Cache Memory"], tag: "Logic", hint: "These physical circuits take one or more binary inputs and produce a single binary output based on a rule." },
    { chapter: 5, question: "Which logic gate only outputs 'TRUE' (1) if BOTH of its inputs are 'TRUE' (1)?", options: ["AND gate", "OR gate", "XOR gate", "NAND gate"], tag: "Logic Gates", hint: "It requires Input A '____' Input B to both be true." },
    { chapter: 5, question: "Which logic gate outputs 'TRUE' (1) if AT LEAST ONE of its inputs is 'TRUE' (1)?", options: ["OR gate", "AND gate", "NOR gate", "XOR gate"], tag: "Logic Gates", hint: "If Input A is true, it passes. If Input B is true, it passes. If both are true, it passes." },
    { chapter: 5, question: "Which logic gate reverses the input, outputting 0 if the input is 1, and 1 if the input is 0?", options: ["NOT gate (Inverter)", "NAND gate", "XOR gate", "NOR gate"], tag: "Logic Gates", hint: "It does exactly the opposite of whatever you tell it to do." },
    { chapter: 5, question: "How is human-readable code (like Python or JavaScript) understood by the hardware?", options: ["It is translated into binary machine code by a compiler or interpreter so the CPU can execute it.", "The operating system reads the syntax and executes the functions directly in the CPU's cache.", "The code is compressed into an executable file that runs independently of the processor.", "The CPU parses the programming language natively using its built-in microcode."], tag: "Abstraction", hint: "The computer needs a translator to turn English-like syntax into 1s and 0s." },
    { chapter: 5, question: "What system is commonly used to translate binary numbers into text characters (like letters and punctuation)?", options: ["ASCII or Unicode", "TCP/IP Protocols", "Hexadecimal Encoding", "Boolean Algebra"], tag: "Data Representation", hint: "It is an encoding standard where a specific binary sequence is mapped to a specific symbol, like 01000001 mapping to the letter 'A'." },
    { chapter: 5, question: "When data is actively being processed by the computer's logic, where is it temporarily held for lightning-fast access?", options: ["RAM (Random Access Memory)", "The Solid State Drive (SSD)", "The Basic Input/Output System (BIOS)", "Virtual Memory (Pagefile)"], tag: "Hardware", hint: "It is short-term memory. Once the power turns off, this memory gets wiped clean." },
    { chapter: 5, question: "What is the 'Fetch-Decode-Execute' cycle?", options: ["The process the CPU uses to retrieve a binary instruction, understand what it means, and carry it out.", "The process of transferring data from the hard drive to RAM for faster access.", "The method a compiler uses to translate high-level code into machine language.", "The sequence of steps an operating system uses to boot up the computer."], tag: "Processing", hint: "This cycle happens billions of times per second inside the processor to handle logic." },
    { chapter: 5, question: "Why do programmers sometimes use Hexadecimal (Base-16) numbers instead of Binary (Base-2)?", options: ["Hexadecimal allows long strings of binary to be written much shorter and is easier for humans to read.", "Hexadecimal is processed twice as fast by the CPU because it uses a base-16 logic system.", "Hexadecimal requires less physical storage space on a hard drive than binary code.", "Hexadecimal is the only language that modern graphic cards can natively understand."], tag: "Data Representation", hint: "It is an abstraction tool. Grouping 4 bits into 1 hex character saves space and reduces human error when reading code." },
    { chapter: 5, question: "How do computers implement visual outputs (like images) using binary data?", options: ["By dividing the screen into tiny pixels and assigning a binary color code to each one.", "By converting digital signals into continuous analog waveforms displayed on the monitor.", "By rendering vector graphics directly from the CPU to the display without pixelation.", "By mapping individual transistors to specific coordinates on the display's glass surface."], tag: "Output", hint: "Every digital picture is a grid of tiny squares, and each square has a specific RGB number assigned to it." },
    { chapter: 5, question: "What determines how many logical operations a computing system can perform per second?", options: ["The clock speed of the CPU, measured in Gigahertz (GHz).", "The total bandwidth of the motherboard's front-side bus.", "The amount of available Random Access Memory (RAM).", "The number of threads available in the operating system."], tag: "Processing", hint: "A 3.0 GHz processor completes 3 billion 'ticks' or cycles per second." }
];
// unit3Pool.js
const unit3Pool = [
    // CHAPTER 6: STORING DATA (Standards: 3A-DA-09, 3A-DA-10)
    { chapter: 6, question: "What is the fundamental difference between Analog and Digital data?", options: ["Analog data is continuous and infinitely variable, while digital data is broken down into discrete, distinct steps.", "Analog data is processed exclusively by the CPU, while digital data is handled by the GPU.", "Analog data refers to text documents, while digital data refers exclusively to multimedia files like audio and video.", "Analog data is transmitted using binary code, while digital data relies on continuous waveforms."], tag: "Data Types", hint: "Think of a smooth ramp vs. a staircase. One flows continuously; the other moves in specific increments." },
    { chapter: 6, question: "How does a computer represent real-world text characters (like 'A' or '?')?", options: ["By assigning a specific binary number (bit representation) to each character using a standardized encoding system like ASCII or Unicode.", "By compiling the characters directly into hexadecimal hardware addresses for the CPU.", "By translating the font style and size into a mathematical vector equation.", "By mapping the physical keyboard strokes to corresponding IP addresses on the network."], tag: "Bit Representation", hint: "There is a massive dictionary that says '01000001' equals 'A'." },
    { chapter: 6, question: "What is 'Lossless' compression?", options: ["A method of reducing file size that allows the exact original data to be perfectly reconstructed without losing any details.", "A data transfer method that guarantees zero packet loss over an unstable network connection.", "A file encryption technique that removes metadata to ensure user privacy is maintained.", "A storage protocol that compresses files by converting all text into lowercase binary."], tag: "Compression", hint: "ZIP files use this method because if you compress a text document, you cannot afford to lose even a single comma." },
    { chapter: 6, question: "When would it be most appropriate to use 'Lossy' compression?", options: ["When storing audio or video files where minor losses in human-perceptible quality are acceptable to save significant storage space.", "When compiling a high-level programming language into an executable file for distribution.", "When backing up a relational database containing critical financial transactions.", "When encrypting highly sensitive government documents for cloud storage."], tag: "Compression", hint: "If you remove some audio frequencies that the human ear can barely hear anyway, the MP3 file becomes much smaller." },
    { chapter: 6, question: "What does 'Metadata' refer to?", options: ["Data that describes other data, such as the date a photo was taken or the author of a document.", "The core source code of an operating system's kernel.", "Temporary data stored in the CPU cache to accelerate processing speeds.", "The primary payload of a data packet being routed across a network."], tag: "Metadata", hint: "It is the 'label on the box' rather than the contents inside the box." },
    { chapter: 6, question: "Why is it important to carefully choose how and where data is stored?", options: ["Because the storage method impacts accessibility, security, cost, and the speed at which the data can be retrieved.", "Because solid-state drives require specific file formats to prevent hardware degradation.", "Because cloud storage algorithms automatically alter the data type of uploaded files.", "Because different operating systems can only access data stored on proprietary hardware architectures."], tag: "Data Storage", hint: "Storing medical records on an unencrypted public cloud has different trade-offs than storing them on a secure local server." },
    { chapter: 6, question: "What is a 'Data Dictionary'?", options: ["A centralized repository of information about data, explaining what each piece of data means, its format, and how it is used.", "A built-in operating system library that stores pre-compiled algorithms for software developers.", "A network protocol used to translate domain names into IP addresses.", "An automated script that spell-checks user inputs in a database form."], tag: "Organization", hint: "If a database has a column named 'Cust_Stat', this tool tells you that it means 'Customer Status' and accepts values of 1 or 0." },
    { chapter: 6, question: "How is an image stored digitally?", options: ["The image is divided into a grid of pixels, and each pixel is assigned a binary value representing its specific color.", "The image is saved as a continuous analog wave that the monitor decodes in real-time.", "The CPU generates a 3D polygonal mesh and wraps it with a pre-rendered texture.", "The visual data is converted into a structured query language (SQL) database."], tag: "Bit Representation", hint: "Zoom in close enough on a digital photo, and you will see the individual tiny colored squares." },
    { chapter: 6, question: "What is the tradeoff of using a higher 'sampling rate' when recording digital audio?", options: ["The audio quality is higher and more accurate to the original sound, but the file size will be much larger.", "The audio file becomes smaller and easier to stream, but the bass frequencies are entirely lost.", "The recording process requires less CPU power, but the audio metadata becomes corrupted.", "The digital signal processes faster, but it limits the file format to proprietary extensions."], tag: "Tradeoffs", hint: "Taking more 'snapshots' of the sound wave per second means you capture more detail, but you have to store all those extra snapshots." },
    { chapter: 6, question: "Which of the following is an example of 'structured data'?", options: ["A spreadsheet containing student names, ID numbers, and grades organized neatly into rows and columns.", "A folder containing thousands of unindexed digital photographs from a recent event.", "A collection of social media posts, comments, and varying emojis.", "A continuous audio stream captured during a live video conference."], tag: "Organization", hint: "This type of data is highly organized, easily searchable, and usually fits perfectly into a database." },
    { chapter: 6, question: "What does it mean if a system's data storage is highly 'Scalable'?", options: ["The system can easily handle a growing amount of data or users without failing or requiring a complete redesign.", "The storage drive automatically compresses old files to maintain a fixed file size over time.", "The hardware can physically adjust its temperature based on the amount of data being processed.", "The data architecture is restricted to local area networks to ensure peak performance speeds."], tag: "Tradeoffs", hint: "Think of a cloud server that seamlessly adds more capacity on Black Friday when millions of people are shopping." },
    { chapter: 6, question: "How many distinct values can be represented by a single byte (8 bits) of data?", options: ["256", "16", "128", "512"], tag: "Bit Representation", hint: "Calculate 2 to the power of 8." },
    { chapter: 6, question: "What happens to data when you 'delete' a file from a standard hard drive?", options: ["The pointer to the file is removed, marking the space as available, but the actual data remains until it is overwritten.", "The operating system immediately overwrites the data sectors with zeros to prevent recovery.", "The file is permanently transferred to the CPU's cache and then purged from memory.", "The physical magnetic sectors on the drive are demagnetized and cannot be used again."], tag: "Data Storage", hint: "This is why data recovery experts can often restore 'deleted' files if you act quickly enough." },
    { chapter: 6, question: "Why would a company choose to store data on local servers rather than in the cloud?", options: ["To maintain complete physical control and security over highly sensitive data without relying on a third-party internet connection.", "To ensure that their databases are automatically indexed by global search engines.", "Because local servers inherently use lossy compression to maximize storage space.", "To allow distributed remote teams to access files faster than a centralized cloud provider."], tag: "Tradeoffs", hint: "Banks and hospitals often prefer to keep their servers locked in their own basements for compliance reasons." },
    { chapter: 6, question: "If a text file is compressed using a lossless algorithm, what happens when it is uncompressed?", options: ["The resulting file is 100% identical to the original file, byte for byte.", "The file retains its core data but loses hidden metadata like author and creation date.", "The text format is slightly altered, requiring the user to manually restore the line breaks.", "The uncompressed file will be permanently converted into a read-only PDF document."], tag: "Compression", hint: "The algorithm 'zips' it up safely and 'unzips' it perfectly." },

    // CHAPTER 7: MASTERING SPREADSHEETS & DATA TOOLS (Standards: 3A-DA-11, 3B-DA-05, 3B-DA-06)
    { chapter: 7, question: "What is the primary purpose of a Data Visualization?", options: ["To graphically represent data using charts, graphs, or maps to make patterns, trends, and outliers easier to understand.", "To convert unstructured data into structured relational databases automatically.", "To increase the processing speed of complex mathematical formulas within a spreadsheet.", "To compress large data sets so they consume less physical storage space on the hard drive."], tag: "Visualization", hint: "A picture is worth a thousand numbers." },
    { chapter: 7, question: "Which of the following describes 'Big Data'?", options: ["Extremely large data sets that may be analyzed computationally to reveal patterns, trends, and associations, especially relating to human behavior.", "A specific type of high-level programming language used exclusively for database management.", "Data that has been upscaled to a higher resolution using artificial intelligence algorithms.", "A hardware standard that requires hard drives to have at least 10 terabytes of storage capacity."], tag: "Big Data", hint: "It refers to the massive volume of information generated globally every second, like social media posts, GPS tracking, and purchase histories." },
    { chapter: 7, question: "What does the process of 'Data Mining' involve?", options: ["Using automated tools to search through large datasets to discover hidden patterns and extract usable information.", "The process of dedicating a computer's processing power to solve cryptography for cryptocurrency.", "Extracting uncompressed video files from a cloud server to local storage.", "Writing manual SQL queries to delete redundant rows from a relational database."], tag: "Data Analysis", hint: "You are 'digging' through mountains of numbers looking for the 'gold' (insights)." },
    { chapter: 7, question: "In a spreadsheet, what does the term 'Aggregation' mean?", options: ["Gathering and summarizing data, such as finding the total sum, average, or count of a group of numbers.", "Splitting a single cell's contents into multiple columns based on a specific delimiter.", "Linking two separate spreadsheet files together so they update simultaneously.", "Applying conditional formatting rules to highlight specific outliers in a dataset."], tag: "Spreadsheets", hint: "When you use functions like =SUM() or =AVERAGE(), you are performing this action." },
    { chapter: 7, question: "When creating a data visualization to show how parts relate to a whole (e.g., market share percentages), which chart type is usually best?", options: ["A Pie Chart", "A Line Chart", "A Scatter Plot", "A Histogram"], tag: "Visualization", hint: "It represents a complete 100% 'pizza', divided into slices." },
    { chapter: 7, question: "What is an Interactive Dashboard?", options: ["A visual interface that displays key metrics and allows users to filter, sort, or drill down into the data in real-time.", "A background operating system process that monitors network traffic and hardware temperatures.", "An automated script that regularly backs up a database to an off-site server.", "A hardware component used to connect multiple monitors to a single desktop workstation."], tag: "Visualization", hint: "Unlike a static report, users can click on elements to explore the data dynamically." },
    { chapter: 7, question: "Why is 'Data Cleaning' (or scrubbing) an essential first step before analyzing a dataset?", options: ["Because datasets often contain errors, duplicates, or missing values that will skew the results and lead to incorrect conclusions.", "Because raw data is automatically encrypted and must be scrubbed to be human-readable.", "Because spreadsheets have a strict file size limit and cleaning removes excess metadata.", "Because uncleaned data will crash the computer's CPU during the visualization process."], tag: "Data Analysis", hint: "Garbage in, garbage out. If your data is flawed, your insights will be too." },
    { chapter: 7, question: "Which type of chart is best suited for showing trends or changes in data over a period of time?", options: ["A Line Chart", "A Pie Chart", "A Scatter Plot", "A Radar Chart"], tag: "Visualization", hint: "It connects data points across the X-axis (usually representing time) to show an upward or downward slope." },
    { chapter: 7, question: "What is the purpose of a 'Pivot Table' in spreadsheet software?", options: ["To quickly summarize, reorganize, and group large amounts of data without altering the original dataset.", "To establish a permanent relational link between two different spreadsheet files.", "To automatically generate predictive algorithms based on historical data inputs.", "To convert numeric data into unstructured text paragraphs for reporting."], tag: "Spreadsheets", hint: "It allows you to 'pivot' your perspective, easily calculating things like total sales per region with just a few clicks." },
    { chapter: 7, question: "How can data collection tools introduce bias into a dataset?", options: ["If the collection method only reaches a specific demographic, the data will not accurately represent the entire population.", "By applying a lossless compression algorithm that slightly alters numerical values.", "By automatically rounding floating-point numbers to the nearest whole integer.", "By failing to encrypt the collected data, allowing third parties to modify the results."], tag: "Data Collection", hint: "If you conduct a survey about internet usage but only ask people who are already on an online forum, your results will be skewed." },
    { chapter: 7, question: "What does it mean to use data to 'communicate a clear claim'?", options: ["Using evidence from the data and appropriate visualizations to support a specific argument or conclusion.", "Writing a technical manual on how to format the data into a structured database.", "Broadcasting an unfiltered dataset to an open-source public repository.", "Using a cryptographic hash function to verify the authenticity of a digital document."], tag: "Communication", hint: "Numbers alone don't tell a story. You have to interpret the patterns to prove a point." },
    { chapter: 7, question: "In data analysis, what is an 'Outlier'?", options: ["A data point that differs significantly from other observations in the dataset.", "A variable that is explicitly excluded from a database schema during its creation.", "A value that causes a spreadsheet function to return a syntax error.", "A type of chart used exclusively for displaying geographical coordinates."], tag: "Data Analysis", hint: "If everyone in a class scores between 70 and 80 on a test, but one person scores a 10, that score stands far outside the norm." },
    { chapter: 7, question: "Why might a business use interactive visualizations instead of static charts for their executives?", options: ["Executives can filter the dashboard by specific dates or regions to explore complex questions on their own.", "Interactive charts require significantly less RAM and processing power to render than static images.", "Interactive visualizations automatically update the underlying source database when clicked.", "Static charts are incompatible with modern cloud storage platforms."], tag: "Visualization", hint: "It empowers the user to ask their own questions of the data by clicking and dragging sliders." },
    { chapter: 7, question: "What is a 'Correlation' in data analysis?", options: ["A statistical relationship showing that two variables tend to move or change together.", "A confirmed cause-and-effect interaction where one variable directly controls another.", "A spreadsheet function that merges multiple datasets into a single cohesive table.", "The process of standardizing text formats across a relational database column."], tag: "Patterns", hint: "Just because ice cream sales and sunburns both go up in the summer, it doesn't mean eating ice cream *causes* sunburns. They are just related." },
    { chapter: 7, question: "Which of the following is crucial when selecting tools to analyze large datasets?", options: ["Ensuring the tool has the processing power and scalability to handle millions of rows without crashing.", "Ensuring the tool uses lossy compression to minimize the file size of the generated reports.", "Selecting a tool that entirely relies on local CPU cache rather than cloud infrastructure.", "Making sure the tool can automatically convert all qualitative data into numerical values."], tag: "Big Data", hint: "A standard Excel file breaks down if you give it 2 million rows. You need specialized software built for heavy lifting." },

    // CHAPTER 8: COMPUTATIONAL MODELING (Standards: 3A-DA-10, 3A-DA-12, 3B-DA-07)
    { chapter: 8, question: "What is a Computational Model?", options: ["A mathematical or algorithmic representation of a real-world system or process used to simulate behavior and make predictions.", "A server architecture designed specifically to host large-scale relational databases.", "A hardware prototype used to test the thermal limits of a new central processing unit.", "A specific type of high-level programming language used to develop web applications."], tag: "Modeling", hint: "Scientists use these to predict the weather or simulate how a disease might spread without having to do real-world experiments." },
    { chapter: 8, question: "Why do computational models rely heavily on 'Abstraction'?", options: ["Because simulating every single detail of reality is impossible, so models must simplify the system to focus only on the most important variables.", "Because abstraction forces the model to run using low-level machine code for maximum efficiency.", "Because models must obscure the underlying mathematical algorithms to protect intellectual property.", "Because abstraction ensures the simulation outputs raw binary data rather than graphical charts."], tag: "Abstraction", hint: "A traffic simulator doesn't need to know the color of the driver's eyes; it just needs to know the speed and size of the cars." },
    { chapter: 8, question: "How is a 'Simulation' different from a static Model?", options: ["A simulation is the active running of a computational model over time to observe how the system behaves under different conditions.", "A simulation only deals with theoretical math, while a model uses real-world empirical data.", "A model requires user input to function, whereas a simulation runs entirely independently of hardware.", "There is no functional difference; they are interchangeable terms for the same software process."], tag: "Simulation", hint: "The model is the set of rules (the engine). This term describes turning the engine on and watching what happens." },
    { chapter: 8, question: "What is the primary purpose of building a computational model?", options: ["To test specific hypotheses, explore 'what-if' scenarios, and predict future outcomes of complex systems.", "To permanently store vast amounts of unstructured data for later retrieval.", "To compile high-level programming scripts into executable binary applications.", "To automate the maintenance and security protocols of a local network."], tag: "Modeling", hint: "It allows researchers to ask 'What happens if we change X?' safely inside a computer." },
    { chapter: 8, question: "What makes a real-world system 'complex' in the context of modeling?", options: ["It has many interacting elements or variables whose relationships are difficult to predict without computational help.", "It requires a supercomputer equipped with multiple GPUs to render its graphical interface.", "It utilizes more than three different programming languages within its source code.", "It requires continuous, real-time data streaming from satellites to function properly."], tag: "Complex Systems", hint: "The global climate is a prime example: ocean currents, air pressure, solar radiation, and human activity all impact each other simultaneously." },
    { chapter: 8, question: "When evaluating a computational model, what does it mean to assess its 'validity'?", options: ["Determining if the model accurately represents the real-world phenomenon it is supposed to simulate.", "Checking if the model's source code contains any syntax or logic errors that would cause a crash.", "Verifying that the simulation completes its run within the allotted processing time.", "Ensuring the model is built using an open-source framework rather than proprietary software."], tag: "Evaluation", hint: "If your gravity simulator shows objects floating upward when dropped, it is not a valid representation of Earth's physics." },
    { chapter: 8, question: "Why might a computational model's predictions be wrong?", options: ["The model may have excluded important variables, relied on inaccurate initial data, or made incorrect assumptions about relationships.", "The system's RAM may have automatically overwritten the algorithmic logic during execution.", "The simulation likely used lossless compression, which inherently distorts output data.", "The model was run on a local server rather than a distributed cloud computing network."], tag: "Evaluation", hint: "A model is only as good as the rules and data you feed into it." },
    { chapter: 8, question: "What is a 'Hypothesis' in relation to computational modeling?", options: ["A testable prediction or proposed explanation about how the system will behave under specific conditions.", "An established algorithm that has been mathematically proven to have zero margin of error.", "The baseline set of raw data uploaded into the simulation before it begins running.", "A built-in diagnostic tool that checks the hardware for potential processing failures."], tag: "Hypothesis", hint: "You build the model to see if this 'educated guess' turns out to be true." },
    { chapter: 8, question: "How do models support the refinement of hypotheses?", options: ["By running the simulation, researchers can compare the output to their expectations, identify flaws, and adjust their rules or assumptions.", "By using predictive text generation to automatically rewrite the research paper's conclusions.", "By translating the results into multiple programming languages to check for hardware compatibility.", "By automatically generating new source code that bypasses the need for human analysis."], tag: "Evaluation", hint: "If the output doesn't match reality, you go back to the drawing board, tweak your rules, and try again." },
    { chapter: 8, question: "Which of the following scenarios is BEST suited for computational modeling?", options: ["Predicting the spread of an infectious disease through a densely populated city over a 30-day period.", "Calculating the exact total sum of a company’s quarterly financial spreadsheet.", "Translating a large unstructured text document from English to Mandarin.", "Compressing a high-resolution video file to be sent via an email attachment."], tag: "Modeling", hint: "You need a computer when there are thousands of interacting variables changing rapidly." },
    { chapter: 8, question: "In a model representing an ecosystem, what would 'variables' represent?", options: ["The specific elements that can change, such as the population size of predators, the amount of rainfall, or the temperature.", "The constant, unchanging laws of physics hardcoded into the simulation's engine.", "The specific bits and bytes allocated to the program in the computer's RAM.", "The user interface sliders and buttons utilized by the researcher."], tag: "Variables", hint: "These are the dials and sliders you can adjust to test different 'what-if' scenarios." },
    { chapter: 8, question: "What is the danger of 'Overfitting' a computational model?", options: ["Creating a model that perfectly matches historical data but is so narrowly focused that it fails to predict future events accurately.", "Assigning too much processing power to the model, causing the hardware to overheat and fail.", "Generating too many graphical outputs, which clutters the data visualization dashboard.", "Using too many variables, causing the simulation to loop endlessly without producing an output."], tag: "Evaluation", hint: "It's like memorizing the exact answers to a practice test without learning the concepts; you'll fail the real test when the numbers change." },
    { chapter: 8, question: "How do you test the relationships among different elements of data in a model?", options: ["By isolating and changing one variable at a time to observe how it impacts the other elements in the simulation.", "By increasing the clock speed of the CPU to see if the simulation renders more quickly.", "By applying a data mining algorithm to search the model for hidden syntax errors.", "By merging the model's database with an external dataset to check for duplicates."], tag: "Relationships", hint: "If you want to know if temperature affects plant growth, you only change the temperature slider and leave the rainfall slider alone." },
    { chapter: 8, question: "Why are random number generators often used in computational models?", options: ["To simulate the natural unpredictability and chance events that occur in real-world systems.", "To continuously alter the hardware's MAC address to prevent network tracking during the simulation.", "To assign unique primary keys to the database records being processed by the algorithm.", "To prevent the CPU cache from overflowing by randomly dropping less important data packets."], tag: "Complex Systems", hint: "Reality isn't a perfect script. Things like weather patterns or human behavior always have an element of randomness." },
    { chapter: 8, question: "What is an important tradeoff to consider when deciding how much detail to include in a simulation?", options: ["Including more detail increases accuracy but requires significantly more processing power and time to run.", "Including more detail reduces the file size of the simulation but makes the code harder to read.", "Including more detail ensures perfect 100% accuracy but restricts the model to local area networks.", "Including more detail simplifies the user interface but limits the number of variables that can be exported."], tag: "Tradeoffs", hint: "If you try to simulate every single atom in a raindrop, your computer will freeze before the storm even starts." }
];

