const unit8Pool = [
    // CHAPTER 18: ARTIFICIAL INTELLIGENCE & SOCIETY (Standards: 9-12.IC.C.3, 9-12.IC.C.4, 9-12.AP.A.1, 9-12.AP.A.2)
    { chapter: 18, question: "What is the primary difference between Traditional Programming and Machine Learning (a subset of AI)?", options: ["Traditional programming relies on hard-coded rules written by humans, while machine learning algorithms learn patterns directly from large datasets to make predictions.", "Traditional programming uses compiled languages like C++, whereas machine learning strictly requires interpreted languages like Python.", "Machine learning utilizes deterministic logic gates, while traditional programming relies entirely on probabilistic heuristic searches.", "Traditional programming requires continuous internet access to compile, while machine learning operates exclusively on local hardware."], tag: "Machine Learning", hint: "Instead of telling the computer 'if it has four wheels, it is a car', you show it a million pictures of cars until it learns the pattern itself." },
    { chapter: 18, question: "How does AI drive a 'Recommendation Engine' (like Netflix or YouTube)?", options: ["It analyzes the input of your past behavior and compares it against patterns from millions of other users to output highly personalized content suggestions.", "It uses a brute-force search algorithm to chronologically list the most recently uploaded content on the server.", "It requires developers to manually tag and assign specific demographics to every individual piece of media.", "It relies on decentralized blockchain ledgers to securely verify which media files are currently trending globally."], tag: "AI Systems", hint: "If a million people who liked 'Movie A' also liked 'Movie B', and you just watched 'Movie A', the system knows what to suggest next." },
    { chapter: 18, question: "What is 'Algorithmic Bias' in Artificial Intelligence?", options: ["When an AI system produces unfair, prejudiced, or discriminatory outcomes because it was trained on flawed, unrepresentative, or historically biased human data.", "A hardware defect inside the GPU that causes the neural network to calculate floating-point variables incorrectly.", "The intentional encryption of a machine learning model to prevent third-party developers from accessing its source code.", "A cybersecurity protocol that automatically restricts network access based on the geographic IP address of the user."], tag: "Bias", hint: "If you train an AI to hire people using resumes from the 1950s, the AI will learn the prejudices of the 1950s." },
    { chapter: 18, question: "What is the purpose of 'Training Data' in Machine Learning?", options: ["It is the initial dataset provided to the algorithm so it can 'learn' relationships, build its internal model, and test its accuracy before being deployed in the real world.", "It is the compiled binary code that tells the central processing unit how to allocate memory for the neural network.", "It is a standardized library of syntax rules used by developers to write error-free artificial intelligence scripts.", "It is the final output generated by the AI after it successfully completes a complex pattern-recognition task."], tag: "Machine Learning", hint: "An AI doesn't know what a dog is until you show it thousands of labeled examples. Those examples are this type of data." },
    { chapter: 18, question: "What does 'Natural Language Processing' (NLP) enable a computer to do?", options: ["Understand, interpret, and generate human language (text or speech) in a meaningful way, powering tools like Siri, Alexa, and chatbots.", "Automatically translate high-level programming languages like Java into low-level assembly code for the CPU.", "Compress large text documents into smaller binary files to reduce the amount of physical storage required on a server.", "Utilize cryptographic hashing to securely transmit voice communications over an unencrypted public Wi-Fi network."], tag: "AI Systems", hint: "It bridges the gap between binary code and human conversation." },
    { chapter: 18, question: "How do Autonomous Vehicles utilize 'Computer Vision'?", options: ["By analyzing real-time inputs from cameras and sensors to identify objects (like pedestrians, stop signs, and lane markers) and make driving decisions.", "By connecting to a centralized satellite database that dictates the exact speed and trajectory the vehicle must follow at all times.", "By emitting high-frequency radio waves to map the terrain physically without requiring any optical lenses or cameras.", "By using recursive loop algorithms to calculate the shortest possible route on a pre-downloaded static GPS map."], tag: "AI Systems", hint: "The car needs 'eyes' to 'see' the world around it and react instantly." },
    { chapter: 18, question: "In AI game theory, what is a 'Decision Tree'?", options: ["A model that branches out to show all possible moves and counter-moves in a game, helping the AI calculate the path that leads to the best outcome.", "A specific type of hardware architecture that limits the amount of RAM an AI can use during competitive gameplay.", "A relational database schema used to store the historical results of every game previously played by the algorithm.", "A cryptographic method used to ensure that human players cannot hack or modify the game's internal variables."], tag: "Algorithms", hint: "If I do X, the human might do Y or Z. If they do Y, I will do A. The algorithm maps out these branches to find the winning path." },
    { chapter: 18, question: "When playing a complex game like Chess, why must an AI use a 'Heuristic' instead of analyzing every single possible future move?", options: ["Because the 'Search Space' (total possible moves) is so astronomically large that calculating them all perfectly would take too much time and computing power.", "Because competitive gaming regulations legally prohibit artificial intelligence from calculating more than three moves ahead.", "Because deterministic algorithms like heuristics are mathematically guaranteed to win every game without fail.", "Because the AI must rely on continuous cloud computing access, and calculating every move would exceed standard bandwidth limits."], tag: "Algorithms", hint: "A heuristic is a 'rule of thumb' or a smart shortcut. The AI evaluates 'is this a generally good board position?' rather than calculating 50 turns deep." },
    { chapter: 18, question: "What is the Turing Test designed to evaluate?", options: ["A machine's ability to exhibit intelligent behavior equivalent to, or indistinguishable from, that of a human being in conversation.", "The maximum clock speed and processing efficiency of a computer specifically designed to run deep learning algorithms.", "The ethical and moral implications of deploying an autonomous AI system in a real-world, high-risk environment.", "Whether a neural network can successfully bypass CAPTCHA security protocols without human intervention."], tag: "Ethics", hint: "If a human is chatting with a computer via text and cannot tell it's a computer, the machine passes this famous test." },
    { chapter: 18, question: "What is a major ethical concern regarding the rise of 'Deepfakes' powered by AI?", options: ["They can be used to generate highly realistic but entirely fake audio and video, leading to massive societal impacts like political misinformation, fraud, and defamation.", "They require such immense processing power that their creation contributes significantly to global hardware shortages.", "They utilize open-source code libraries that frequently introduce severe security vulnerabilities into personal devices.", "They automatically overwrite existing digital media files on cloud servers, permanently destroying historical video archives."], tag: "Ethics", hint: "Seeing is no longer believing. A computer can make it look and sound like someone said something they never actually said." },
    { chapter: 18, question: "What is a 'Neural Network' in the context of AI?", options: ["A computing system inspired by the structure of the human brain, using interconnected layers of 'nodes' to process complex patterns like images or language.", "A localized intranet protocol that allows multiple IoT devices to share processing power securely within a single household.", "A specific type of relational database designed to quickly query text-based records using structured SQL commands.", "A centralized cloud architecture that exclusively handles the routing of encrypted DNS requests across the internet."], tag: "AI Systems", hint: "It simulates neurons firing and connecting to solve problems that are too messy for standard yes/no programming." },
    { chapter: 18, question: "How does AI Automation impact the workforce and the economy?", options: ["It can eliminate repetitive or dangerous jobs while simultaneously creating new roles in tech and maintenance, fundamentally shifting the skills required in the economy.", "It inherently decentralizes the global economy by replacing all fiat currency with AI-managed cryptographic tokens.", "It standardizes all hardware manufacturing, forcing companies to adopt a single universal operating system for robotic workers.", "It legally mandates that corporations migrate all human-resources data to publicly accessible open-source ledgers."], tag: "Societal Impact", hint: "Just as the tractor changed farming, AI changes data analysis. The jobs don't disappear entirely; they evolve." },
    { chapter: 18, question: "What does the 'Minimax' algorithm do when an AI plays a game against a human?", options: ["It assumes the human will play perfectly and chooses the move that minimizes the AI's maximum possible loss.", "It utilizes a random number generator to select an unpredictable move, intentionally confusing the human opponent.", "It systematically memorizes the human player's behavioral patterns and mimics their exact playing style.", "It calculates the absolute shortest path to victory and ignores any defensive moves entirely."], tag: "Algorithms", hint: "It looks at the board and says: 'What is the worst thing the human can do to me next turn? Okay, how do I make that worst-case scenario as painless as possible?'" },
    { chapter: 18, question: "Why is 'Privacy' a massive concern with modern AI systems?", options: ["AI algorithms require massive amounts of data to function effectively, often collecting detailed personal information about users without their explicit understanding.", "AI systems are inherently open-source, meaning any collected user data is automatically published to public code repositories.", "Because AI completely bypasses traditional network firewalls, making it impossible to encrypt data packets during transmission.", "AI relies on hardware-level keystroke logging, meaning all passwords typed on a device are permanently stored in the CPU cache."], tag: "Ethics", hint: "The AI is 'hungry' for data to learn from. Sometimes, that data includes your location, purchase history, and private messages." },
    { chapter: 18, question: "When describing an AI model, what is the 'State' of the system?", options: ["The current specific configuration or snapshot of the problem, such as the exact layout of pieces on a chessboard at a given moment.", "The geographic server location where the machine learning algorithm's primary database is physically hosted.", "The Boolean true/false variable that dictates whether the neural network is currently actively learning or standing by.", "The compiled binary file format of the artificial intelligence software before it is executed by the processor."], tag: "Algorithms", hint: "Before the AI makes a decision, it has to evaluate 'where everything is right now'. That snapshot is the state." }
];

async function seedDatabase() {
    console.log("Connecting to MariaDB...");
    const connection = await mysql.createConnection(dbConfig);
    
const targetedExams = ['cs-unit-0', 'cs-unit-1', 'cs-unit-2', 'cs-unit-3', 'cs-unit-4', 'cs-unit-5', 'cs-unit-6', 'cs-unit-7', 'cs-unit-8'];

    console.log("Ensuring parent diagnostic markers are initialized in 'exams' table...");
    for (const examId of targetedExams) {
        const [existing] = await connection.execute('SELECT exam_id FROM exams WHERE exam_id = ?', [examId]);
        if (existing.length === 0) {
            const unitNumber = examId.replace('cs-unit-', '');
            await connection.execute(
                'INSERT INTO exams (exam_id, title, total_points, course_id) VALUES (?, ?, ?, ?)',
                [examId, `Computer Science Unit ${unitNumber} Pre-Assessment`, 100, '10003GS']
            );
            console.log(`-> Set up missing assignment parent node: ${examId}`);
        }
    }

console.log("Clearing out old records for handled units...");
    await connection.execute('DELETE FROM questions WHERE exam_id IN (?, ?, ?, ?, ?, ?, ?, ?, ?)', targetedExams);

    console.log("Resetting table numbering...");
    // This forces the database to recount and start the next ID at the lowest available number
    await connection.execute('ALTER TABLE questions AUTO_INCREMENT = 1');

const allQuestions = [
        ...unit0Pool.map(q => ({ ...q, exam_id: 'cs-unit-0' })),
        ...unit1Pool.map(q => ({ ...q, exam_id: 'cs-unit-1' })),
        ...unit2Pool.map(q => ({ ...q, exam_id: 'cs-unit-2' })),
        ...unit3Pool.map(q => ({ ...q, exam_id: 'cs-unit-3' })),
        ...unit4Pool.map(q => ({ ...q, exam_id: 'cs-unit-4' })),
        ...unit5Pool.map(q => ({ ...q, exam_id: 'cs-unit-5' })),
        ...unit6Pool.map(q => ({ ...q, exam_id: 'cs-unit-6' })),
        ...unit7Pool.map(q => ({ ...q, exam_id: 'cs-unit-7' })),
        ...unit8Pool.map(q => ({ ...q, exam_id: 'cs-unit-8' }))
    ];

    console.log(`Starting migration of ${allQuestions.length} questions...`);

    const queryStr = `
        INSERT INTO questions (exam_id, chapter_number, question_text, option_a, option_b, option_c, option_d, correct_answer, study_hint, concept_tag) 
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
    `;

let count = 0;
    for (const q of allQuestions) {
        // Ensure options exist
        const opts = q.options || [];
        
        // FIX: Use explicit null check instead of || to allow chapter a
        // The issue was that 'chapter || null' treats 0 as falsy and converts it to null
        const chapterNum = (q.chapter === undefined || q.chapter === null) ? null : q.chapter;
        
        // Define values, forcing undefined to null to prevent driver errors
        const values = [
            q.exam_id || null,
            chapterNum,
            q.question || "Unknown Question",
            opts[0] || null,
            opts[1] || null,
            opts[2] || null,
            opts[3] || null,
            opts[0] || null, // Assuming first option is the correct one
            q.hint || null,
            q.tag || null
        ];

        // Debugging: Check for undefined before execution
        if (values.includes(undefined)) {
            console.error("CRITICAL ERROR: Undefined value found in question:", q);
            throw new Error("Bind parameters contain undefined");
        }

        await connection.execute(queryStr, values);
        count++;
    }

    console.log(`\nMigration complete! Saved ${count} questions.`);
    await connection.end();
}

seedDatabase().catch(err => {
    console.error("Migration script crashed:", err);
});